async function* asyncGenerator() {
  const data = ['a', 'b', 'c'];
  for (const item of data) {
    // simulate async delay
    await new Promise(resolve => setTimeout(resolve, 100));
    yield item;
  }
}

async function printItems() {
  for await (const letter of asyncGenerator()) {
    console.log(letter);
  }
}

printItems();

async function* fetchPaginatedData(url) {
  let nextUrl = url;
  while (nextUrl) {
    const response = await fetch(nextUrl);
    const data = await response.json();
    for (const item of data.results) {
      yield item;
    }
    nextUrl = data.next; // assume API provides a next page URL or null
  }
}

(async () => {
  for await (const user of fetchPaginatedData('https://api.example.com/users')) {
    console.log(user.name);
  }
})();

import fs from 'fs';
import readline from 'readline';

async function* readLines(filePath) {
  const fileStream = fs.createReadStream(filePath);
  const rl = readline.createInterface({ input: fileStream });

  for await (const line of rl) {
    yield line;
  }
}

(async () => {
  for await (const line of readLines('bigfile.txt')) {
    console.log(`Line: ${line}`);
  }
})();

function updateItems(items) {
  items.forEach(item => {
    const element = document.getElementById(item.id);
    element.textContent = item.value;
  });
}

// Calling with many items
