function updateItemsOptimized(items) {
  const fragment = document.createDocumentFragment();
  items.forEach(item => {
    const element = document.createElement('div');
    element.id = item.id;
    element.textContent = item.value;
    fragment.appendChild(element);
  });
  const container = document.getElementById('container');
  container.innerHTML = '';
  container.appendChild(fragment);
}

updateItemsOptimized(largeArray);

interface User {
  id: number;
  name: string;
  email: string;
}

type PartialUser = {
  [K in keyof User]?: User[K];
};

const partialUser: PartialUser = {
  name: "Alice"
};

type ReadonlyUser = {
  readonly [K in keyof User]: User[K];
};

const readonlyUser: ReadonlyUser = {
  id: 1,
  name: "Bob",
  email: "bob@example.com"
};

// readonlyUser.id = 2; // Error: Cannot assign to 'id' because it is a read-only property.

type NullableUser = {
  [K in keyof User]: User[K] | null;
};

const nullableUser: NullableUser = {
  id: null,
  name: "Carol",
  email: null
};

interface UserWithMethod {
  id: number;
  name: string;
  getEmail: () => string;
}

type ReadonlyExceptMethods<T> = {
  readonly [K in keyof T]: T[K] extends Function ? T[K] : Readonly<T[K]>;
};

const user: ReadonlyExceptMethods<UserWithMethod> = {
  id: 5,
  name: "Dan",
  getEmail: () => "dan@example.com"
};

// user.id = 6; // Error: Cannot assign to 'id' because it is a read-only property.
user.getEmail = () => "new@example.com"; // Allowed: methods are not readonly

function printId(id: number | string) {
  if (typeof id === 'string') {
    // Inside this block, TypeScript knows 'id' is a string
    console.log(id.toUpperCase());
  } else {
    // Here, 'id' must be a number
    console.log(id.toFixed(2));
  }
}

printId('abc'); // Output: ABC
printId(123);   // Output: 123.00

function greet(name: string | null) {
  if (name) {
    // TypeScript now knows 'name' is definitely a string
    console.log(`Hello, ${name.toUpperCase()}!`);
  } else {
    console.log('Hello, guest!');
  }
}

greet('Alice');  // Output: Hello, ALICE!
greet(null);     // Output: Hello, guest!

interface Fish {
  swim: () => void;
}

interface Bird {
  fly: () => void;
}

function isFish(pet: Fish | Bird): pet is Fish {
  return (pet as Fish).swim !== undefined;
}

function move(pet: Fish | Bird) {
  if (isFish(pet)) {
    pet.swim(); // Safe to call swim
  } else {
    pet.fly();  // Safe to call fly
  }
}

from flask import Flask, jsonify, request

app = Flask(__name__)

# Simulated device states
smart_home_devices = {
    'light': {'status': 'off'},
    'thermostat': {'temperature': 22}  # temperature in Celsius
}

@app.route('/light', methods=['GET'])
def get_light_status():
    """Get the current status of the light."""
    status = smart_home_devices['light']['status']
    return jsonify({'light_status': status})

@app.route('/light', methods=['POST'])
def set_light_status():
    """Turn the light on or off."""
    data = request.get_json()
    if not data or 'status' not in data:
        return jsonify({'error': 'Missing light status'}), 400
    status = data['status'].lower()
    if status not in ['on', 'off']:
        return jsonify({'error': 'Invalid status. Use "on" or "off".'}), 400
    smart_home_devices['light']['status'] = status
    return jsonify({'message': f'Light turned {status}'}), 200

@app.route('/thermostat', methods=['GET'])
def get_thermostat_temperature():
    """Get the current thermostat temperature."""
    temperature = smart_home_devices['thermostat']['temperature']
    return jsonify({'temperature': temperature})

@app.route('/thermostat', methods=['POST'])
def set_thermostat_temperature():
    """Set the thermostat temperature."""
    data = request.get_json()
    if not data or 'temperature' not in data:
        return jsonify({'error': 'Missing temperature value'}), 400
    try:
        temperature = float(data['temperature'])
    except ValueError:
        return jsonify({'error': 'Temperature must be a number'}), 400
    if temperature < 10 or temperature > 30:
        return jsonify({'error': 'Temperature must be between 10 and 30 degrees Celsius'}), 400
    smart_home_devices['thermostat']['temperature'] = temperature
    return jsonify({'message': f'Thermostat set to {temperature}°C'}), 200

if __name__ == '__main__':
    app.run(debug=True)

CREATE TABLE Products (
  ProductID INT PRIMARY KEY IDENTITY(1,1),
  ProductName VARCHAR(100) NOT NULL,
  Quantity INT NOT NULL DEFAULT 0
);

CREATE PROCEDURE AddProduct
  @ProductName VARCHAR(100),
  @InitialQuantity INT
AS
BEGIN
  INSERT INTO Products (ProductName, Quantity)
  VALUES (@ProductName, @InitialQuantity);
END;

CREATE PROCEDURE IncreaseStock
  @ProductID INT,
  @Amount INT
AS
BEGIN
  UPDATE Products
  SET Quantity = Quantity + @Amount
  WHERE ProductID = @ProductID;
END;

CREATE PROCEDURE DecreaseStock
  @ProductID INT,
  @Amount INT
AS
BEGIN
  IF EXISTS (SELECT 1 FROM Products WHERE ProductID = @ProductID AND Quantity >= @Amount)
  BEGIN
    UPDATE Products
    SET Quantity = Quantity - @Amount
    WHERE ProductID = @ProductID;
  END
  ELSE
  BEGIN
    RAISERROR('Not enough stock to complete this operation.', 16, 1);
  END
END;

CREATE PROCEDURE GetInventory
AS
BEGIN
  SELECT ProductID, ProductName, Quantity FROM Products;
END;

